        yield* Console.log(`Markdown files in ${resolvedDir}:`);
        yield* Console.log("");
        for (const file of tree) {
          yield* Console.log(`  ${file.relativePath}`);
        }
        yield* Console.log("");
        yield* Console.log(`Total: ${tree.length} files`);
      }
    })
