     5→
     6→import { Effect } from "effect";
     7→import { unified } from "unified";
     8→import remarkParse from "remark-parse";
     9→import remarkGfm from "remark-gfm";
    10→import { visit } from "unist-util-visit";
    11→import matter from "gray-matter";
    12→import * as crypto from "node:crypto";
    13→import type { Root, Heading, Link, Image, Code, Text, Parent } from "mdast";
    14→
    15→import type {
    16→  MdDocument,
    17→  MdSection,
    18→  MdLink,
    19→  MdCodeBlock,
    20→  HeadingLevel,
    21→  ParseError,
    22→  DocumentMetadata,
    23→} from "../core/types.js";
    24→import { countTokensApprox, countWords } from "../utils/tokens.js";
    25→
    26→// ============================================================================
    27→// Parser Configuration
    28→// ============================================================================
    29→
    30→const processor = unified().use(remarkParse).use(remarkGfm);
    31→
    32→// ============================================================================
    33→// Helper Functions
    34→// ============================================================================
    35→
    36→const generateId = (input: string): string => {
    37→  return crypto.createHash("md5").update(input).digest("hex").slice(0, 12);
    38→};
    39→
    40→const slugify = (text: string): string => {
    41→  return text
    42→    .toLowerCase()
    43→    .replace(/[^\w\s-]/g, "")
    44→    .replace(/\s+/g, "-")
    45→    .replace(/-+/g, "-")
    46→    .trim();
    47→};
    48→
    49→const isInternalLink = (href: string): boolean => {
    50→  if (href.startsWith("http://") || href.startsWith("https://")) return false;
    51→  if (href.startsWith("mailto:")) return false;
    52→  if (href.startsWith("#")) return true;
    53→  if (href.endsWith(".md") || href.includes(".md#")) return true;
    54→  return !href.includes("://");
    55→};
    56→
    57→const extractPlainText = (node: Parent | Root): string => {
    58→  const texts: string[] = [];
    59→  visit(node, "text", (textNode: Text) => {
    60→    texts.push(textNode.value);
    61→  });
    62→  return texts.join(" ");
    63→};
    64→
    65→const getNodeEndLine = (node: { position?: { end?: { line?: number } } }): number => {
    66→  return node.position?.end?.line ?? 0;
    67→};
    68→
    69→const getNodeStartLine = (node: { position?: { start?: { line?: number } } }): number => {
    70→  return node.position?.start?.line ?? 0;
    71→};
    72→
    73→// ============================================================================
    74→// Section Extraction
    75→// ============================================================================
    76→
    77→interface RawSection {
    78→  heading: string;
    79→  level: HeadingLevel;
    80→  startLine: number;
    81→  endLine: number;
    82→  contentStartLine: number;
    83→  contentNodes: unknown[];
    84→}
    85→
    86→const extractRawSections = (tree: Root): RawSection[] => {
    87→  const sections: RawSection[] = [];
    88→  const headings: { heading: string; level: HeadingLevel; line: number; index: number }[] = [];
    89→
    90→  // First pass: collect all headings with their positions
    91→  tree.children.forEach((node, index) => {
    92→    if (node.type === "heading") {
    93→      const heading = node as Heading;
    94→      headings.push({
    95→        heading: extractPlainText(heading),
    96→        level: heading.depth as HeadingLevel,
    97→        line: getNodeStartLine(node),
    98→        index,
    99→      });
   100→    }
   101→  });
   102→
   103→  // Second pass: create sections from headings
   104→  headings.forEach((h, i) => {
   105→    const nextHeading = headings[i + 1];
   106→    const endIndex = nextHeading ? nextHeading.index : tree.children.length;
   107→
   108→    // Get content nodes between this heading and the next
   109→    const contentNodes = tree.children.slice(h.index + 1, endIndex);
   110→    const lastContentNode = contentNodes[contentNodes.length - 1];
   111→    const endLine = lastContentNode
   112→      ? getNodeEndLine(lastContentNode)
   113→      : h.line;
   114→
   115→    sections.push({
   116→      heading: h.heading,
   117→      level: h.level,
   118→      startLine: h.line,
   119→      endLine,
   120→      contentStartLine: h.line + 1,
   121→      contentNodes,
   122→    });
   123→  });
   124→
   125→  return sections;
   126→};
   127→
   128→const buildSectionHierarchy = (
   129→  rawSections: RawSection[],
   130→  docId: string,
   131→  lines: string[]
   132→): MdSection[] => {
   133→  const result: MdSection[] = [];
   134→  const stack: { section: MdSection; level: number }[] = [];
   135→
   136→  for (const raw of rawSections) {
   137→    const contentLines = lines.slice(raw.startLine - 1, raw.endLine);
   138→    const content = contentLines.join("\n");
   139→    const plainText = extractSectionPlainText(raw.contentNodes as Parent[]);
   140→
   141→    const hasCode = (raw.contentNodes as { type: string }[]).some((n) => n.type === "code");
   142→    const hasList = (raw.contentNodes as { type: string }[]).some((n) => n.type === "list");
   143→    const hasTable = (raw.contentNodes as { type: string }[]).some((n) => n.type === "table");
   144→
   145→    const section: MdSection = {
   146→      id: `${docId}-${slugify(raw.heading)}`,
   147→      heading: raw.heading,
   148→      level: raw.level,
   149→      content,
   150→      plainText,
   151→      startLine: raw.startLine,
   152→      endLine: raw.endLine,
   153→      children: [],
   154→      metadata: {
   155→        wordCount: countWords(plainText),
   156→        tokenCount: countTokensApprox(content),
   157→        hasCode,
   158→        hasList,
   159→        hasTable,
   160→      },
   161→    };
   162→
   163→    // Build hierarchy: find parent for this section
   164→    while (stack.length > 0 && stack[stack.length - 1]!.level >= raw.level) {
   165→      stack.pop();
   166→    }
   167→
   168→    if (stack.length === 0) {
   169→      result.push(section);
   170→    } else {
   171→      const parent = stack[stack.length - 1]!;
   172→      (parent.section.children as MdSection[]).push(section);
   173→    }
   174→
   175→    stack.push({ section, level: raw.level });
   176→  }
   177→
   178→  return result;
   179→};
   180→
   181→const extractSectionPlainText = (nodes: Parent[]): string => {
   182→  const texts: string[] = [];
   183→  for (const node of nodes) {
   184→    if ("value" in node && typeof node.value === "string") {
   185→      texts.push(node.value);
   186→    } else if ("children" in node) {
   187→      texts.push(extractPlainText(node));
   188→    }
   189→  }
   190→  return texts.join(" ");
   191→};
   192→
   193→// ============================================================================
   194→// Link Extraction
   195→// ============================================================================
   196→
   197→const extractLinks = (tree: Root, docId: string): MdLink[] => {
   198→  const links: MdLink[] = [];
   199→  let currentSectionId = docId;
   200→
   201→  visit(tree, (node) => {
   202→    if (node.type === "heading") {
   203→      currentSectionId = `${docId}-${slugify(extractPlainText(node as Heading))}`;
   204→    }
   205→
   206→    if (node.type === "link") {
   207→      const link = node as Link;
   208→      const internal = isInternalLink(link.url);
   209→      links.push({
   210→        type: internal ? "internal" : "external",
   211→        href: link.url,
   212→        text: extractPlainText(link),
   213→        sectionId: currentSectionId,
   214→        line: getNodeStartLine(node),
   215→      });
   216→    }
   217→
   218→    if (node.type === "image") {
   219→      const img = node as Image;
   220→      links.push({
   221→        type: "image",
   222→        href: img.url,
   223→        text: img.alt ?? "",
   224→        sectionId: currentSectionId,
   225→        line: getNodeStartLine(node),
   226→      });
   227→    }
   228→  });
   229→
   230→  return links;
   231→};
   232→
   233→// ============================================================================
   234→// Code Block Extraction
   235→// ============================================================================
   236→
   237→const extractCodeBlocks = (tree: Root, docId: string): MdCodeBlock[] => {
   238→  const codeBlocks: MdCodeBlock[] = [];
   239→  let currentSectionId = docId;
   240→
   241→  visit(tree, (node) => {
   242→    if (node.type === "heading") {
   243→      currentSectionId = `${docId}-${slugify(extractPlainText(node as Heading))}`;
   244→    }
   245→
   246→    if (node.type === "code") {
   247→      const code = node as Code;
   248→      codeBlocks.push({
   249→        language: code.lang ?? null,
   250→        content: code.value,
   251→        sectionId: currentSectionId,
   252→        startLine: getNodeStartLine(node),
   253→        endLine: getNodeEndLine(node),
   254→      });
   255→    }
   256→  });
   257→
   258→  return codeBlocks;
   259→};
   260→
   261→// ============================================================================
   262→// Main Parser Function
   263→// ============================================================================
   264→
   265→export interface ParseOptions {
   266→  readonly path?: string;
   267→  readonly lastModified?: Date;
   268→}
   269→
   270→export const parse = (
   271→  content: string,
   272→  options: ParseOptions = {}
   273→): Effect.Effect<MdDocument, ParseError> =>
   274→  Effect.gen(function* () {
   275→    const path = options.path ?? "unknown";
   276→    const docId = generateId(path);
   277→    const now = new Date();
   278→
   279→    // Extract frontmatter
   280→    const { data: frontmatter, content: markdownContent } = matter(content);
   281→
   282→    // Parse markdown to AST
   283→    const tree = processor.parse(markdownContent) as Root;
   284→
   285→    // Split content into lines for reference
   286→    const lines = markdownContent.split("\n");
   287→
   288→    // Extract sections
   289→    const rawSections = extractRawSections(tree);
   290→    const sections = buildSectionHierarchy(rawSections, docId, lines);
   291→
   292→    // Extract links and code blocks
   293→    const links = extractLinks(tree, docId);
   294→    const codeBlocks = extractCodeBlocks(tree, docId);
   295→
   296→    // Determine title (first H1 or filename)
   297→    const firstH1 = sections.find((s) => s.level === 1);
   298→    const title =
   299→      firstH1?.heading ??
   300→      (typeof frontmatter["title"] === "string" ? frontmatter["title"] : null) ??
   301→      path.split("/").pop()?.replace(/\.md$/, "") ??
   302→      "Untitled";
   303→
   304→    // Calculate metadata
   305→    const totalContent = sections.map((s) => s.content).join("\n");
   306→    const metadata: DocumentMetadata = {
   307→      wordCount: countWords(totalContent),
   308→      tokenCount: countTokensApprox(content),
   309→      headingCount: sections.length,
   310→      linkCount: links.length,
   311→      codeBlockCount: codeBlocks.length,
   312→      lastModified: options.lastModified ?? now,
   313→      indexedAt: now,
   314→    };
   315→
   316→    const document: MdDocument = {
   317→      id: docId,
   318→      path,
   319→      title,
   320→      frontmatter,
   321→      sections,
   322→      links,
   323→      codeBlocks,
   324→      metadata,
   325→    };
   326→
   327→    return document;
   328→  });
   329→
   330→/**
   331→ * Parse a markdown file from the filesystem
   332→ */
   333→export const parseFile = (
   334→  filePath: string
   335→): Effect.Effect<MdDocument, ParseError | { _tag: "IoError"; message: string; path: string }> =>
   336→  Effect.gen(function* () {
   337→    const fs = yield* Effect.promise(() => import("node:fs/promises"));
   338→
   339→    let content: string;
   340→    let stats: Awaited<ReturnType<typeof fs.stat>>;
   341→
   342→    try {
   343→      [content, stats] = yield* Effect.all([
   344→        Effect.promise(() => fs.readFile(filePath, "utf-8")),
   345→        Effect.promise(() => fs.stat(filePath)),
   346→      ]);
   347→    } catch (error) {
   348→      return yield* Effect.fail({
   349→        _tag: "IoError" as const,
   350→        message: error instanceof Error ? error.message : "Unknown error",
   351→        path: filePath,
   352→      });
   353→    }
   354→
   355→    return yield* parse(content, {
   356→      path: filePath,
   357→      lastModified: stats.mtime,
   358→    });
   359→  });
   360→

