const getNodeEndLine = (node: { position?: { end?: { line?: number } } }): number => {
  return node.position?.end?.line ?? 0;
};

const getNodeStartLine = (node: { position?: { start?: { line?: number } } }): number => {
  return node.position?.start?.line ?? 0;
};

