      heading: raw.heading,
      level: raw.level,
      content,
      plainText,
      startLine: raw.startLine,
      endLine: raw.endLine,
      children: [],
      metadata: {
        wordCount: countWords(plainText),
        tokenCount: countTokensApprox(content),
        hasCode,
        hasList,
        hasTable,
