    19→
    20→const formatJson = (obj: unknown, pretty: boolean): string => {
    21→  return pretty ? JSON.stringify(obj, null, 2) : JSON.stringify(obj);
    22→};
    23→
    24→const printSection = (section: MdSection, indent: number = 0): string => {
    25→  const prefix = "  ".repeat(indent);
    26→  const bullet = section.level === 1 ? "#" : "-";
    27→  let output = `${prefix}${bullet} ${section.heading} (${section.metadata.tokenCount} tokens)\n`;
    28→
    29→  for (const child of section.children) {
    30→    output += printSection(child, indent + 1);
    31→  }
    32→
    33→  return output;
    34→};
    35→
    36→const isMarkdownFile = (filename: string): boolean => {
    37→  return filename.endsWith(".md") || filename.endsWith(".mdx");
    38→};
