     5→import { Effect } from "effect";
     6→import { watch } from "chokidar";
     7→import * as path from "node:path";
     8→
     9→import { buildIndex, type IndexOptions } from "./indexer.js";
    10→import { createStorage, indexExists } from "./storage.js";
    11→
    12→// ============================================================================
    13→// Watcher Types
    14→// ============================================================================
    15→
    16→export interface WatcherOptions extends IndexOptions {
    17→  readonly debounceMs?: number;
    18→  readonly onIndex?: (result: { documentsIndexed: number; duration: number }) => void;
    19→  readonly onError?: (error: Error) => void;
    20→}
    21→
    22→export interface Watcher {
    23→  readonly stop: () => void;
    24→}
    25→
    26→// ============================================================================
    27→// Watcher Implementation
    28→// ============================================================================
    29→
    30→const isMarkdownFile = (filePath: string): boolean =>
    31→  filePath.endsWith(".md") || filePath.endsWith(".mdx");
    32→
    33→export const watchDirectory = (
    34→  rootPath: string,
    35→  options: WatcherOptions = {}
    36→): Effect.Effect<Watcher, Error> =>
    37→  Effect.gen(function* () {
    38→    const resolvedRoot = path.resolve(rootPath);
    39→    const storage = createStorage(resolvedRoot);
    40→    const debounceMs = options.debounceMs ?? 300;
    41→
    42→    // Ensure index exists
    43→    const exists = yield* indexExists(storage);
    44→    if (!exists) {
    45→      // Build initial index
    46→      const result = yield* buildIndex(resolvedRoot, options);
    47→      options.onIndex?.({ documentsIndexed: result.documentsIndexed, duration: result.duration });
    48→    }
    49→
    50→    // Create a debounce queue
    51→    const pendingPaths = new Set<string>();
    52→    let debounceTimer: NodeJS.Timeout | null = null;
    53→
    54→    const scheduleReindex = () => {
    55→      if (debounceTimer) {
    56→        clearTimeout(debounceTimer);
    57→      }
    58→
    59→      debounceTimer = setTimeout(async () => {
    60→        if (pendingPaths.size === 0) return;
    61→
    62→        pendingPaths.clear();
